1	export class GameOfLife {
2	  private static readonly MIN_SURVIVAL_NEIGHBORS = 2;
3	  private static readonly MAX_SURVIVAL_NEIGHBORS = 3;
4	  private cells: [number, number][] = [];
5	
6	  getCells() {
7	    return this.cells;
8	  }
9	
10	  addCell(x: number, y: number) {
11	    this.cells.push([x, y]);
12	  }
13	
14	  countNeighbors(x: number, y: number): number {
15	    let count = 0;
16	    for (let dx = -1; dx <= 1; dx++) {
17	      for (let dy = -1; dy <= 1; dy++) {
18	        if (dx === 0 && dy === 0) continue;
19	        if (this.cells.some(cell => cell[0] === x + dx && cell[1] === y + dy)) {
20	          count++;
21	        }
22	      }
23	    }
24	    return count;
25	  }
26	
27	  nextGeneration(): [number, number][] {
28	    if (this.cells.length === 0) {
29	      return [];
30	    }
31	    const [x, y] = this.cells[0];
32	    const neighbors = this.countNeighbors(x, y);
33	    if (
34	      neighbors >= GameOfLife.MIN_SURVIVAL_NEIGHBORS &&
35	      neighbors <= GameOfLife.MAX_SURVIVAL_NEIGHBORS
36	    ) {
37	      return [[x, y]];
38	    }
39	    return [];
40	  }
41	}
