nextGeneration(): [number, number][] {
  if (this.cells.length === 0) {
    return [];
  }
  const [x, y] = this.cells[0];
  const neighbors = this.countNeighbors(x, y);
  const result: [number, number][] = [];

  // Check survival of existing cell
  if (
    neighbors >= GameOfLife.MIN_SURVIVAL_NEIGHBORS &&
    neighbors <= GameOfLife.MAX_SURVIVAL_NEIGHBORS
  ) {
    result.push([x, y]);
  }

  // Check resurrection of dead cells
  const checkedCells = new Set<string>();
  for (const [cx, cy] of this.cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = cx + dx;
        const ny = cy + dy;
        const key = `${nx},${ny}`;

        // Skip if already checked or is a living cell
        if (checkedCells.has(key) || this.cells.some(cell => cell[0] === nx && cell[1] === ny)) {
          continue;
        }
        checkedCells.add(key);

        // Resurrect if exactly 3 neighbors
        if (this.countNeighbors(nx, ny) === 3) {
          result.push([nx, ny]);
        }
      }
    }
  }

  return result;
}

